INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "春咲 ひより", "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 0, "お！\nあそこに困ってそうな人発見！", 1, 0, 0, 1, 1, 0, 1.4, 1001, 2, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "草野 優衣", "わ、わたし、\nなに言ってるんだろ\nあはは…", 0, "大切な人を\n守れるようになりたい…って", 1, 0, 0, 1, 1, 0, 1.4, 1002, 2, "みんなみたいに\nわたしも強くならなきゃ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "士条 怜", "少しは磨かれると思いますよ。", 0, "キミに必要な集中力と感性が", 1, 0, 0, 1, 1, 0, 1.4, 1003, 2, "フェンシングを始めてみては？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "穂高 みそぎ", "みそぎはねぇ、\nかくれんぼやりたい！", 0, "今日はなにして遊ぶ？", 1, 0, 0, 1, 1, 0, 1.5, 1004, 2, "ねぇ、にいちゃん！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "風宮 あかり", "私といっしょに…\nいかない？", 0, "ねぇ…", 1, 0, 0, 1, 1, 0, 1.4, 1006, 2, "風宮あかりです");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "出雲 宮子", "食べ物の恨みは怖いのー", 0, "プリンたべたいのー", 1, 0, 0, 1, 1, 0, 1.5, 1007, 2, "出雲宮子なのー");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "虹村 雪", "いいよ。\n見られることは運命さ…", 0, "キミもボクの美貌に\n吸い寄せられたんだね。", 1, 0, 0, 1, 1, 0, 1.4, 1008, 2, "ボクは虹村雪。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "柊杏奈", "人呼んで「疾風の冥姫」!!", 0, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1, 0, 0, 1, 1, 0, 1.4, 1009, 2, "フッ…聞いて後悔するがいい！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "姫宮 真歩", "ほんまおおきにやわ～♪", 0, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1, 0, 0, 1, 1, 0, 1.5, 1010, 2, "マホマホ王国のプリンセス、\nまほ姫どす");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "衣之咲 璃乃", "ここで会ったが\n100年目～！", 0, "生き別れたお兄ちゃんを探して\n三千世界！", 1, 0, 0, 1, 1, 0, 1.4, 1011, 2, "衣之咲璃乃です！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "柏崎 初音", "…って、お願い！\n誰にも言わないでおいて～！", 0, "ち、超能力って…\n何のことかな～？", 1, 0, 0, 1, 1, 0, 1.4, 1012, 2, "私はハツネ、\n結構強いんだよ。\nきらーん☆");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "美波 鈴奈", "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 0, "一応カリスマ読モJKやってまっす！", 1, 0, 0, 1, 1, 0, 1.4, 1016, 2, "ちょす！\n美波鈴奈だよ～♪");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "喜屋武 香織", "でも、沖縄もとってもいいとこさー", 0, "東京は遊園地みたいなところさー", 1, 0, 0, 1, 1, 0, 1.4, 1017, 2, "はいたーい。\n喜屋武香織さー。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "支倉 伊緒", "イオちゃんって呼んでね。", 0, "先生って呼ばれるのは\nくすぐったいから", 1, 0, 0, 1, 1, 0, 1.4, 1018, 2, "支倉伊緒です。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "茜 ミミ", "ミミをおいてかないでぇ～", 0, "あ！/\お兄ちゃ～ん\nまってよ～", 1, 0, 0, 1, 1, 0, 1.5, 1020, 2, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "栗林 くるみ", "ふぇぇぇぇぇん……", 0, "あの……\nふぇ……", 1, 0, 0, 1, 1, 0, 1.5, 1021, 2, "あ…あの…えっと…\n栗…林…くるみ…です……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "風宮 より", "なんてありがとうございます！", 0, "こんな私に貴重な時間を\n割いていただき、", 1, 0, 0, 1, 1, 0, 1.4, 1022, 2, "風宮よりです。\nあああああ！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "北条 綾音", "私こっち行きたいー\nね、早く早くー", 0, "おにいちゃんどこいくの？\nえ？", 1, 0, 0, 1, 1, 0, 1.5, 1023, 2, "私、アヤネ！\nぷうきちと一緒についてってあげるね！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "天野 すずめ", "これて何か違う…\nあああすみません！", 0, "ふ、不束者ですが\nどうぞ末永く…って、", 1, 0, 0, 1, 1, 0, 1.4, 1025, 2, "わっ…わっ…私、\n天野すずめといいます！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "倉石 恵理子", "離しませんわ………\n絶対に…!!", 0, "あなたは…運命の……\n伴侶……", 1, 0, 0, 1, 1, 0, 1.4, 1027, 2, "……クスクス…私は\n…倉石恵理子……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "佐々木 咲恋", "…そうでしょ？？", 0, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1, 0, 0, 1, 1, 0, 1.4, 1028, 2, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "桜井 望", "あはは、\n私もまだまだだなぁ～", 0, "ぇっと…\nキミ、私のこと知らないの?!", 1, 0, 0, 1, 1, 0, 1.4, 1029, 2, "桜井望だよ！\nよろしくねっ");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ニノン・ジュベール", "ショーグン、\nワタシと一緒に天下統一デース！", 0, "初めまして、\n私はニノン・ジュベール申すデス！", 1, 0, 0, 1, 1, 0, 1.4, 1030, 2, "デケデケデンっ！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "上喜 しのぶ", "おかしいですね……", 0, "でもって私の隣にいるのが……\nえ、見えない？", 1, 0, 0, 1, 1, 0, 1.4, 1031, 2, "上喜しのぶです。\n手元のドクロが父です。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "野戸まひる", "そう、\nオラのボケに突っ込める相方が…！", 0, "けんども\nそれには足りないモンが…", 1, 0, 0, 1, 1, 0, 1.5, 1033, 2, "目指すはビッグな\nお笑い芸人だっぺ！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "綾瀬 ゆかり", "ちょ\nちょっと一杯飲んできます…！", 0, "ちょっと緊張しちゃって…", 1, 0, 0, 1, 1, 0, 1.4, 1034, 2, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "氷川 鏡華", "これ以上お話しすることは…\nないです！", 0, "知らない人とは話しちゃいけないので", 1, 0, 0, 1, 1, 0, 1.5, 1036, 2, "氷川鏡華…です");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "柏崎 栞", "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 0, "……あ、アラーム。", 1, 0, 0, 1, 1, 0, 1.4, 1038, 2, "柏崎…栞です。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "双葉 碧", "野に咲く花が、\n唯一の話相手です。", 0, "私、一人も友達がいなくて……", 1, 0, 0, 1, 1, 0, 1.4, 1040, 2, "ふ、双葉碧です。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "三角 千歌", "そう思っています。", 0, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1, 0, 0, 1, 1, 0, 1.4, 1042, 2, "三角千歌です。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "安芸 真琴", "う、疑ってすまなかったな…", 0, "あぁ？\nお前のそいつの仲間か？", 1, 0, 0, 1, 1, 0, 1.4, 1043, 2, "安芸真琴だ。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "イリヤ・オーンスタイン", "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 0, "生けとし生ける全ての者よ！", 1, 0, 0, 1, 1, 0, 1.4, 1044, 2, "わらわこそは夜を総べる者！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "遠見 空花", "ｌク、クウカに何かご用ですか!?", 0, "ぐふふふふ……はっ！", 1, 0, 0, 1, 1, 0, 1.4, 1045, 2, "そこで騎士は妖精を乱暴に……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "宮坂たまき", "う～ん…\n猫ってホントに最高にゃ～♪", 0, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1, 0, 0, 1, 1, 0, 1.4, 1046, 2, "宮坂たまきにゃ♪\n猫はいいにゃよ？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "大神 美冬", "…と思ったら\nバイトの時間だ！\nまたあとでね！", 0, "それでは早速クエストに…", 1, 0, 0, 1, 1, 0, 1.4, 1048, 2, "大神美冬よ！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "星野静流", "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 0, "クエストもバトルも\n掃除も洗濯も", 1, 0, 0, 1, 1, 0, 1.4, 1049, 2, "星野静流だよ！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "玉泉美咲", "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 0, "見ての通りの\nセクシー美少女で", 1, 0, 0, 1, 1, 0, 1.5, 1050, 2, "アタシは玉泉美咲。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "リマ", "？？？？", 0, "？？？？", 1, 0, 0, 1, 1, 0, 1.4, 1052, 2, "？？？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "モニカ・ヴァイスヴィント", "そ、そこまでいうなら\nもらってやる", 0, "菓子でつろうなどと\n稚拙な策を……", 1, 0, 0, 1, 1, 0, 1.5, 1053, 2, "モニカ・ヴァイスヴィントだ。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ペコリーヌ", "そ、そこまでいうなら\nもらってやる", 0, "菓子でつろうなどと\n稚拙な策を……", 1, 0, 0, 1, 1, 0, 1.5, 1058, 2, "モニカ・ヴァイスヴィントだ。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "コッコロ", "そ、そこまでいうなら\nもらってやる", 0, "菓子でつろうなどと\n稚拙な策を……", 1, 0, 0, 1, 1, 0, 1.5, 1059, 2, "モニカ・ヴァイスヴィントだ。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "キャル", "そ、そこまでいうなら\nもらってやる", 0, "菓子でつろうなどと\n稚拙な策を……", 1, 0, 0, 1, 1, 0, 1.5, 1060, 2, "モニカ・ヴァイスヴィントだ。");
